class Solution:
    def nthSuperUglyNumber(self, n: int, primes: List[int]) -> int:
        ugly = [1]
        idx = [0]*len(primes)
        while len(ugly) < n:
            nxt = min(ugly[idx[i]]*primes[i] for i in range(len(primes)))
            ugly.append(nxt)
            for i in range(len(primes)):
                if ugly[idx[i]]*primes[i] == nxt:
                    idx[i] += 1
        return ugly[-1]

